class GeneratedPage {
    get usernameInput() { return cy.get("#username"); }
    get passwordInput() { return cy.get("#password"); }
    get loginButton() { return cy.get("input[type="submit"]"); }

    /** Fill the username field */
    enterUsername(username) { this.usernameInput.type(username); }

    /** Fill the password field */
    enterPassword(password) { this.passwordInput.type(password); }

    /** Click the Login */
    clickLogin() { this.loginButton.click(); }
}

export default new GeneratedPage();

